from piece import Piece

class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('B')
        for row in range(5, 8):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('W')

    def display(self):
        print("  A B C D E F G H")
        for row in range(8):
            print(f"{row + 1} ", end="")
            for col in range(8):
                if self.board[row][col]:
                    print(self.board[row][col].get_symbol(), end=" ")
                else:
                    print(".", end=" ")
            print()

    def is_valid_move(self, from_pos, to_pos):
        row1, col1 = ord(from_pos[0]) - ord('A'), int(from_pos[1]) - 1
        row2, col2 = ord(to_pos[0]) - ord('A'), int(to_pos[1]) - 1
        piece = self.board[row1][col1]

        if not piece or piece.color != 'W':
            return False

        if abs(row2 - row1) == 1 and abs(col2 - col1) == 1:
            if self.board[row2][col2]:
                return False
            return True
        elif abs(row2 - row1) == 2 and abs(col2 - col1) == 2:
            intermediate_row = (row1 + row2) // 2
            intermediate_col = (col1 + col2) // 2
            if self.board[intermediate_row][intermediate_col] and \
               self.board[row2][col2] is None and \
               (self.board[intermediate_row][intermediate_col].color == 'B' if piece.color == 'W' else self.board[intermediate_row][intermediate_col].color == 'W'):
                return True
        return False

    def move(self, from_pos, to_pos):
        row1, col1 = ord(from_pos[0]) - ord('A'), int(from_pos[1]) - 1
        row2, col2 = ord(to_pos[0]) - ord('A'), int(to_pos[1]) - 1
        piece = self.board[row1][col1]
        if piece and self.is_valid_move(from_pos, to_pos):
            self.board[row1][col1] = None
            if abs(row2 - row1) == 2:
                intermediate_row = (row1 + row2) // 2
                intermediate_col = (col1 + col2) // 2
                self.board[intermediate_row][intermediate_col] = None
            self.board[row2][col2] = piece
            if piece.color == 'W' and row2 == 7:
                piece.king()
            elif piece.color == 'B' and row2 == 0:
                piece.king()
        else:
            raise ValueError("Invalid move")

    def check_winner(self):
        white_count = sum(1 for row in self.board for piece in row if piece and piece.color == 'W')
        black_count = sum(1 for row in self.board for piece in row if piece and piece.color == 'B')
        if white_count == 0:
            return 'Black'
        elif black_count == 0:
            return 'White'
        return None
