def is_valid_move(board, start_row, start_col, end_row, end_col):
    # Basic checks for valid move
    if board[start_row][start_col] == ' ' or board[end_row][end_col] != ' ':
        return False
    # Check if the piece is moving in the correct direction
    if (board[start_row][start_col].islower() and end_row < start_row) or \
       (board[start_row][start_col].isupper() and end_row > start_row):
        return False
    # Check if the move is diagonal and one square
    if abs(end_row - start_row) != 1 or abs(end_col - start_col) != 1:
        return False
    return True

def make_move(board, start_row, start_col, end_row, end_col):
    board[end_row][end_col] = board[start_row][start_col]
    board[start_row][start_col] = ' '
    # Check for capturing and update the board accordingly
    if abs(end_row - start_row) == 2:
        mid_row = (start_row + end_row) // 2
        mid_col = (start_col + end_col) // 2
        board[mid_row][mid_col] = ' '
    return board

